// STRY0014064 - Start a Template from a Task
function onSubmit() {

	var table = 'x_153465_discovert_discover_routing_template';
	if(g_form.getActionName() == 'selectAndStartTemplate'){
		// If the form is dirty, ask the user if they would like to save the record
		var saveChangeConfirmation = false;
		var saveMsg = getMessage('Tasker - Modal Save Changes Message');
		if(typeof spModal != 'undefined'){
			var serializeChanges = g_form.serialize(true);
			if(serializeChanges.length>0){
				var changeFieldList = [];
				for (var field in serializeChanges) {
					changeFieldList.push(serializeChanges[field].label.trim());
				}
				var fMsg = changeFieldList.join(', ');					
				saveMsg += "  " + fMsg;
				saveChangeConfirmation = true;
			}
		} else if (typeof spModal == 'undefined' && g_form.modified) {
			saveMsg += JSON.stringify(g_form.modifiedFields);
			saveChangeConfirmation = true;
		}

		// use the variable set above here to show confirmation message.
		if(saveChangeConfirmation){				
			if(confirm(saveMsg)){
				g_form.save();
			} else{
				return false;
			}
		}

		if (typeof spModal != 'undefined' ) {
			spModal.open({
				title: 'Select Template to Start',
				widget: 'tasker_start_from_task',  
				message:'',
				widgetInput: {parentTask:g_form.getUniqueValue()},
				backdrop:'static',
		buttons: [
					{
						label: 'Next'
					},
					{
						label: 'Cancel'
					}					
				],

				size: "lg"
			});
			return false;
		} else {
			// STRY0075793
			var modalForm = new GlideModalForm('Select Template to Start', 'x_153465_discovert_discover_routing_runtime');
			modalForm.addParm('sysparm_query','parent_task='+g_form.getUniqueValue());
			modalForm.render();
			modalForm.setSysID(-1);

			return false;
		}
	}	
}
